// src/pages/admin/AdminDashboard.js
import React, { useEffect, useState } from "react";
import { Box, Grid, Paper, Typography, IconButton, Table, TableHead, TableBody, TableRow, TableCell, Button } from "@mui/material";
import PeopleIcon from "@mui/icons-material/People";
import PersonIcon from "@mui/icons-material/Person";
import VerifiedUserIcon from "@mui/icons-material/VerifiedUser";
import PendingActionsIcon from "@mui/icons-material/PendingActions";
import DirectionsCarIcon from "@mui/icons-material/DirectionsCar";

import {
  getOverview,
  getUsers,
  getRiders,
  getApprovedCaptains,
  getPendingCaptains,
  getRides,
  approveCaptain,
  rejectCaptain,
} from "../../services/adminApi";

export default function AdminDashboard() {
  const [selected, setSelected] = useState("overview");
  const [overview, setOverview] = useState({});
  const [users, setUsers] = useState([]);
  const [riders, setRiders] = useState([]);
  const [approvedCaptains, setApprovedCaptains] = useState([]);
  const [pendingCaptains, setPendingCaptains] = useState([]);
  const [rides, setRides] = useState([]);
  const [loading, setLoading] = useState(true);

  // Fetch all data from backend
  const fetchData = async () => {
    setLoading(true);
    try {
      const overviewRes = await getOverview();
      const usersRes = await getUsers();
      const ridersRes = await getRiders();
      const approvedRes = await getApprovedCaptains();
      const pendingRes = await getPendingCaptains();
      const ridesRes = await getRides();

      setOverview({
        users: usersRes.data.users.length,
        riders: ridersRes.data.riders.length,
        approvedCaptains: approvedRes.data.captains.length,
        pendingCaptains: pendingRes.data.pendingCaptains.length,
        rides: ridesRes.data.rides.length,
      });

      setUsers(usersRes.data.users);
      setRiders(ridersRes.data.riders);
      setApprovedCaptains(approvedRes.data.captains);
      setPendingCaptains(pendingRes.data.pendingCaptains);
      setRides(ridesRes.data.rides);
    } catch (err) {
      console.error("Admin Dashboard fetch error:", err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  const handleApprove = async (id) => {
    await approveCaptain(id);
    fetchData();
  };

  const handleReject = async (id) => {
    await rejectCaptain(id);
    fetchData();
  };

  const cards = [
    { label: "Users", value: overview.users, icon: <PeopleIcon fontSize="large" />, key: "users" },
    { label: "Riders", value: overview.riders, icon: <PersonIcon fontSize="large" />, key: "riders" },
    { label: "Approved Captains", value: overview.approvedCaptains, icon: <VerifiedUserIcon fontSize="large" />, key: "approvedCaptains" },
    { label: "Pending Captains", value: overview.pendingCaptains, icon: <PendingActionsIcon fontSize="large" />, key: "pendingCaptains" },
    { label: "Rides", value: overview.rides, icon: <DirectionsCarIcon fontSize="large" />, key: "rides" },
  ];

  const renderTable = () => {
    switch (selected) {
      case "users":
        return (
          <Table>
            <TableHead>
              <TableRow>
                <TableCell>Full Name</TableCell>
                <TableCell>Email</TableCell>
                <TableCell>Mobile</TableCell>
                <TableCell>Role</TableCell>
                <TableCell>Login Count</TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {users.map(u => (
                <TableRow key={u._id}>
                  <TableCell>{u.fullName}</TableCell>
                  <TableCell>{u.email}</TableCell>
                  <TableCell>{u.mobile}</TableCell>
                  <TableCell>{u.role}</TableCell>
                  <TableCell>{u.loginCount}</TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        );
      case "riders":
        return (
          <Table>
            <TableHead>
              <TableRow>
                <TableCell>Full Name</TableCell>
                <TableCell>Email</TableCell>
                <TableCell>Mobile</TableCell>
                <TableCell>Approval Status</TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {riders.map(r => (
                <TableRow key={r._id}>
                  <TableCell>{r.fullName}</TableCell>
                  <TableCell>{r.email}</TableCell>
                  <TableCell>{r.mobile}</TableCell>
                  <TableCell>{r.approvalStatus}</TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        );
      case "approvedCaptains":
        return (
          <Table>
            <TableHead>
              <TableRow>
                <TableCell>Full Name</TableCell>
                <TableCell>Mobile</TableCell>
                <TableCell>Login Count</TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {approvedCaptains.map(c => (
                <TableRow key={c._id}>
                  <TableCell>{c.fullName}</TableCell>
                  <TableCell>{c.mobile}</TableCell>
                  <TableCell>{c.loginCount}</TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        );
      case "pendingCaptains":
        return (
          <Table>
            <TableHead>
              <TableRow>
                <TableCell>Full Name</TableCell>
                <TableCell>Mobile</TableCell>
                <TableCell>Action</TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {pendingCaptains.map(c => (
                <TableRow key={c._id}>
                  <TableCell>{c.fullName}</TableCell>
                  <TableCell>{c.mobile}</TableCell>
                  <TableCell>
                    <Button color="success" onClick={() => handleApprove(c._id)}>Approve</Button>
                    <Button color="error" onClick={() => handleReject(c._id)}>Reject</Button>
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        );
      case "rides":
        return (
          <Table>
            <TableHead>
              <TableRow>
                <TableCell>Rider</TableCell>
                <TableCell>Captain</TableCell>
                <TableCell>Pickup</TableCell>
                <TableCell>Drop</TableCell>
                <TableCell>Fare</TableCell>
                <TableCell>Status</TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {rides.map(r => (
                <TableRow key={r._id}>
                  <TableCell>{r.riderId?.fullName || "-"}</TableCell>
                  <TableCell>{r.captainId?.fullName || "-"}</TableCell>
                  <TableCell>{r.pickup}</TableCell>
                  <TableCell>{r.drop}</TableCell>
                  <TableCell>{r.fare}</TableCell>
                  <TableCell>{r.status}</TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        );
      default:
        return <Typography>Select a card to view data</Typography>;
    }
  };

  if (loading) return <Typography>Loading...</Typography>;

  return (
    <Box>
      <Typography variant="h4" gutterBottom>
        Rider App - Admin Dashboard
      </Typography>

      <Grid container spacing={2} sx={{ mb: 3 }}>
        {cards.map(card => (
          <Grid item xs={12} sm={6} md={2.4} key={card.label}>
            <Paper
              onClick={() => setSelected(card.key)}
              sx={{
                p: 3,
                textAlign: "center",
                boxShadow: 3,
                borderRadius: 2,
                backgroundColor: selected === card.key ? "#e0f7fa" : "#f5f5f5",
                cursor: "pointer",
                transition: "transform 0.2s",
                "&:hover": { transform: "scale(1.05)" },
              }}
            >
              <IconButton size="large" sx={{ color: "#00796b" }}>
                {card.icon}
              </IconButton>
              <Typography variant="subtitle1">{card.label}</Typography>
              <Typography variant="h5" fontWeight="bold">{card.value}</Typography>
            </Paper>
          </Grid>
        ))}
      </Grid>

      <Paper sx={{ p: 2 }}>
        {renderTable()}
      </Paper>
    </Box>
  );
}
